solution:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scan = new Scanner(System.in);
        System.out.println("Takas edilecek 2 sayıyı giriniz:");
        double n1 = scan.nextDouble();
        double n2 = scan.nextDouble();

        System.out.println("Değiştirmeden önce: " + n1 + " - " + n2);

        // 1. Yol: 3. değişken kullanın
        double temp = n1;
        double originalN1 = n1;
        double originalN2 = n2;

        n1 = n2;
        n2 = temp;
        System.out.println("Değiştirdikten sonra: " + n1 + " - " + n2);

        // Değerleri eski haline getirelim
        n1 = originalN1;
        n2 = originalN2;

        // 2. Yol: 3. değişkeni kullanmayın
        n1 = n1 + n2;
        n2 = n1 - n2;
        n1 = n1 - n2;
        System.out.println("Değiştirdikten sonra: " + n1 + " - " + n2);
    }
}

