public class Main {
    public static void main(String[] args) {
        int[] a = new int[]{-12, 18, -5, 23, -2};
        Arrays.sort(a);
        int minPositive = a[a.length - 1];
        int maxNegative = a[0];
        for (int w : a) {
            if (w >= 0) {
                minPositive = Math.min(minPositive, w);
            }
            if (w < 0) {
                maxNegative = Math.max(maxNegative, w);
            }
        }
        System.out.println("Minimum pozitif: " + minPositive);
        System.out.println("Maksimum negatif: " + maxNegative);
    }
}

