public class Main {
    public static void main(String[] args) {
        int[] arr = new int[]{5, 0, 2, 0, 3};
        int[] brr = new int[arr.length];
        int firstIdx = 0;
        int lastIdx = arr.length - 1;
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] != 0) {
                brr[firstIdx] = arr[i];
                firstIdx++;
            } else {
                brr[lastIdx] = 0;
                lastIdx--;
            }
        }
        System.out.println(Arrays.toString(brr));
    }
}

