        int len = scan.nextInt();
        int arr[] = new int[len];
        System.out.println("Giriş " + len + " dizi öğeleri");
        for (int i = 0; i < len; i++) {
            arr[i] = scan.nextInt();
        }
        System.out.println(Arrays.toString(arr));
        Arrays.sort(arr);
        System.out.println(Arrays.toString(arr));
        int diffOfBigAndSmall = arr[arr.length - 1] - arr[0];
